type Factory<T = any> = () => T;

interface Registration {
  factory: Factory;
  singleton: boolean;
  instance?: any;
}

export class Container {
  private registrations = new Map<string, Registration>();

  register<T>(key: string, factory: Factory<T>): void {
    this.registrations.set(key, { factory, singleton: false });
  }

  registerSingleton<T>(key: string, factory: Factory<T>): void {
    this.registrations.set(key, { factory, singleton: true });
  }

  resolve<T>(key: string): T {
    const reg = this.registrations.get(key);
    if (!reg) {
      throw new Error(`'${key}' not registered`);
    }
    if (reg.singleton) {
      if (reg.instance === undefined) {
        reg.instance = reg.factory();
      }
      return reg.instance;
    }
    return reg.factory();
  }
}
